import React, { useState } from 'react';

export default function AudioExtractor() {
  const [url, setUrl] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(false);

  // Fix 1: Add the explicit type to the event parameter 'e'
  const handleDownload = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!url) return;

    setLoading(true);

    try {
      const response = await fetch('http://localhost:5000/extract', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url }),
      });

      if (!response.ok) throw new Error('Network response failed');

      const blob = await response.blob();
      const downloadUrl = window.URL.createObjectURL(blob);

      const link = document.createElement('a');
      link.href = downloadUrl;
      link.setAttribute('download', 'extracted-audio.mp3'); 

      document.body.appendChild(link);
      link.click();

      // Fix 2: Use modern .remove() directly on the element instead of .parentNode
      link.remove();

      window.URL.revokeObjectURL(downloadUrl);
    } catch (error) {
      console.error("Error downloading file:", error);
      alert("Failed to extract audio.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.backgroundGlow} />
      <div style={styles.card}>
        <div style={styles.badge}>Audio extraction</div>
        <h1 style={styles.title}>Turn any video into a polished MP3</h1>

        <p style={styles.subtitle}>
          Paste a video URL to extract clear audio in seconds.
        </p>

        <div style={styles.searchBox}>
          <input
            style={styles.input}
            type="text"
            placeholder="Paste video URL here..."
            value={url}
            onChange={(e) => setUrl(e.target.value)}
          />

          <button
            style={styles.button}
            onClick={extractAudio}
            disabled={loading || !url.trim()}
          >
            {loading ? "Extracting..." : "Extract MP3"}
          </button>
        </div>

        <div style={styles.infoRow}>
          <span style={styles.infoPill}>⚡ Fast conversion</span>
          <span style={styles.infoPill}>🎵 High-quality audio</span>
          <span style={styles.infoPill}>🔒 Local download</span>
        </div>

        {error && <div style={styles.errorBox}>{error}</div>}
        {loading && (
          <div style={styles.loadingBox}>Processing your video...</div>
        )}
      </div>
    </div>
  );
}
